import{_ as o,o as t,c as a,ag as i}from"./chunks/framework.C9sp7nFj.js";const c=JSON.parse('{"title":"Log out","description":"","frontmatter":{},"headers":[],"relativePath":"guide/logout.md","filePath":"guide/logout.md","lastUpdated":1776620726000}'),l={name:"guide/logout.md"};function s(n,e,r,u,h,g){return t(),a("div",null,[...e[0]||(e[0]=[i('<h1 id="log-out" tabindex="-1">Log out <a class="header-anchor" href="#log-out" aria-label="Permalink to &quot;Log out&quot;">​</a></h1><p>When you need to fully sign out — for example, if you&#39;re handing the phone to someone else, or you need to log in as a different user.</p><h2 id="how" tabindex="-1">How <a class="header-anchor" href="#how" aria-label="Permalink to &quot;How&quot;">​</a></h2><ol><li>Tap the <strong>More</strong> tab</li><li>Scroll to the bottom</li><li>Tap the red <strong>Log out</strong> button</li></ol><p>You&#39;re immediately taken back to the login screen.</p><h2 id="what-log-out-does" tabindex="-1">What log-out does <a class="header-anchor" href="#what-log-out-does" aria-label="Permalink to &quot;What log-out does&quot;">​</a></h2><ul><li>Clears your session token</li><li>Clears your cached PIN hash</li><li>Clears the last-login-email shortcut (so the next user isn&#39;t greeted by your email)</li><li>Clears the biometric enrolment flag</li><li><strong>Keeps any pending offline items</strong> (check-ins, leave, expense) — if the next user is you again and you log back in, they&#39;ll still be there waiting to sync</li></ul><h2 id="what-log-out-does-not-do" tabindex="-1">What log-out does NOT do <a class="header-anchor" href="#what-log-out-does-not-do" aria-label="Permalink to &quot;What log-out does NOT do&quot;">​</a></h2><ul><li>It doesn&#39;t delete your data on the server</li><li>It doesn&#39;t clear your check-in history, leave applications, or payslips (those live on the server and reappear on next login)</li><li>It doesn&#39;t uninstall the app</li><li>It doesn&#39;t clear files already saved to your Documents folder (e.g. downloaded payslip PDFs)</li></ul><h2 id="before-logging-out-sync-first" tabindex="-1">Before logging out: sync first <a class="header-anchor" href="#before-logging-out-sync-first" aria-label="Permalink to &quot;Before logging out: sync first&quot;">​</a></h2><p>If you have <strong>pending offline items</strong> in the queue, they will still be there after logout — but they can only sync while you&#39;re logged in. Best practice:</p><ol><li>Make sure the sync bar says <strong>&quot;Synced now&quot;</strong> before logging out</li><li>If it says <strong>&quot;3 changes pending&quot;</strong>, tap it and wait for sync to complete</li><li>Then log out</li></ol><p>This avoids situations where someone else logs in, syncs their data, and your queued items stay stuck.</p><h2 id="session-timeout-vs-log-out" tabindex="-1">Session timeout vs log-out <a class="header-anchor" href="#session-timeout-vs-log-out" aria-label="Permalink to &quot;Session timeout vs log-out&quot;">​</a></h2><p>These are different:</p><ul><li><strong>Session timeout</strong> (~2 hours of inactivity) — the app asks for your PIN / biometric again, but you stay logged in. Fast to unlock.</li><li><strong>Log out</strong> — full sign-out; next time you need your password.</li></ul><h2 id="next" tabindex="-1">Next <a class="header-anchor" href="#next" aria-label="Permalink to &quot;Next&quot;">​</a></h2><ul><li><a href="/guide/login">Login &amp; PIN</a> (how to come back in)</li><li><a href="/guide/troubleshooting">Troubleshooting</a></li></ul>',18)])])}const f=o(l,[["render",s]]);export{c as __pageData,f as default};
